import React from 'react';
import {
  ShoppingCart,
  Plus,
  Minus,
  Trash2,
  LogOut
} from 'lucide-react';

function CartPage({
  cart,
  user,
  setCurrentPage,
  handleLogout,
  updateCartQuantity,
  removeFromCart
}) {
if (!Array.isArray(cart)) {
  return <div className="p-10">Loading cart...</div>;
}

const total = cart.reduce(
  (sum, item) => sum + item.price * item.quantity,
  0
);

return (
    <div className="min-h-screen bg-gradient-to-b from-slate-50 via-white to-slate-50">
      {/* HEADER */}
      <header className="bg-white shadow-md sticky top-0 z-40 border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <button
            onClick={() => setCurrentPage('products')}
            className="font-semibold"
          >
            ← Continue Shopping
          </button>

          <h1 className="text-2xl font-bold">Shopping Cart</h1>

          <button onClick={handleLogout}>
            <LogOut />
          </button>
        </div>
      </header>

      {/* CART BODY */}
      <div className="max-w-7xl mx-auto px-6 py-8">
        {cart.length === 0 ? (
          <div className="text-center">
            <ShoppingCart size={80} />
            <h2>Your cart is empty</h2>
            <button onClick={() => setCurrentPage('products')}>
              Start Shopping
            </button>
          </div>
        ) : (
          <div className="grid lg:grid-cols-3 gap-8">
            {/* CART ITEMS */}
            <div className="lg:col-span-2">
              {cart.map((item) => {
                const itemId = item.productIdString || item.productId;

                return (
                  <div key={itemId} className="flex gap-4 mb-4">
                    <img
                      src={item.imageUrl}
                      alt={item.productName}
                      width={100}
                    />

                    <div className="flex-1">
                      <h3>{item.productName}</h3>
                      <p>₹{item.price}</p>

                      <div className="flex gap-2">
                        <button onClick={() => updateCartQuantity(itemId, item.quantity - 1)}>
                          <Minus />
                        </button>
                        <span>{item.quantity}</span>
                        <button onClick={() => updateCartQuantity(itemId, item.quantity + 1)}>
                          <Plus />
                        </button>
                      </div>
                    </div>

                    <button onClick={() => removeFromCart(itemId)}>
                      <Trash2 />
                    </button>
                  </div>
                );
              })}
            </div>

            {/* SUMMARY */}
            <div>
              <h3>Order Summary</h3>
              <p>Total: ₹{total}</p>

              <button onClick={() => setCurrentPage('checkout')}>
                Checkout
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default CartPage;
